param (
    # The App Name to pass to the WUA API as the calling application.
    [Parameter()]
    [String]$AppName = "Windows Update API Script",
    # The search criteria to be used.
    [Parameter()]
    [String]$Criteria = "IsInstalled=0 and Type='Software' and IsHidden=0",
    [Parameter()]
    [bool]$ExcludePreviewUpdates = $true,
    [Parameter()]
    [ValidateSet("MU", "WSUS")]
    [string]$Service = 'MU',
    # The http/https fqdn for the Windows Server Update Server
    [Parameter()]
    [string]$WSUSServer
)
  
Function ConvertFrom-InstallationResult {
    [CmdletBinding()]
    param (
        [Parameter()]
        [int]$Result
    )        
    switch ($Result) {
        2 { $Text = 'Succeeded' }
        3 { $Text = 'Succeeded with errors' }
        4 { $Text = 'Failed' }
        5 { $Text = 'Cancelled' }
        Default { $Text = "Unexpected ($Result)" }
    }        
    Return $Text
}

function Write-OutputWithTimeStamp {
    param(
        [string]$Message
    )    
    $Timestamp = Get-Date -Format 'MM/dd/yyyy HH:mm:ss'
    $Entry = '[' + $Timestamp + '] ' + $Message
    Write-Output $Entry
}

Start-Transcript -Path "$env:SystemRoot\Logs\Install-Updates.log"
Write-OutputWithTimeStamp -Message "Starting Windows Update Script with the following parameters:"
Write-Output ( $PSBoundParameters | Format-Table -AutoSize )

Switch ($Service.ToUpper()) {
    'MU' { $ServerSelection = 3; $ServiceId = "7971f918-a847-4430-9279-4a52d1efe18d" }
    'WSUS' { $ServerSelection = 1 }
}        
If ($Service -eq 'MU') {
    $UpdateServiceManager = New-Object -ComObject Microsoft.Update.ServiceManager
    $UpdateServiceManager.ClientApplicationID = $AppName
    $UpdateServiceManager.AddService2("7971f918-a847-4430-9279-4a52d1efe18d", 7, "")
    $null = cmd /c reg.exe ADD "HKLM\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate\AU" /v AllowMUUpdateService /t REG_DWORD /d 1 /f '2>&1'
    Write-OutputWithTimeStamp "Added Registry entry to configure Microsoft Update. Exit Code: [$LastExitCode]"
}
Elseif ($Service -eq 'WSUS' -and $WSUSServer) {
    $null = cmd /c reg.exe ADD "HKLM\Software\Policies\Microsoft\Windows\WindowsUpdate" /v WUServer /t REG_SZ /d $WSUSServer /f '2>&1'
    $null = cmd /c reg.exe ADD "HKLM\Software\Policies\Microsoft\Windows\WindowsUpdate" /v WUStatusServer /t REG_SZ /d $WSUSServer /f '2>&1'
    Write-OutputWithTimeStamp "Added Registry entry to configure WSUS Server. Exit Code: [$LastExitCode]"
}        
$UpdateSession = New-Object -ComObject Microsoft.Update.Session
$updateSession.ClientApplicationID = $AppName   
$UpdateSearcher = New-Object -ComObject Microsoft.Update.Searcher
$UpdateSearcher.ServerSelection = $ServerSelection
If ($ServerSelection -eq 3) {
    $UpdateSearcher.ServiceId = $ServiceId
}
Write-OutputWithTimeStamp -Message "Searching for Updates..."
$SearchResult = $UpdateSearcher.Search($Criteria)
If ($($SearchResult.Updates).Count -gt 0) {
    Write-OutputWithTimeStamp "List of applicable items found for this computer:"
    For ($i = 0; $i -lt $($SearchResult.Updates).Count; $i++) {
        $Update = $SearchResult.Updates[$i]
        Write-Output "$($i + 1) > $($update.Title)"
    }
    $AtLeastOneAdded = $false
    $ExclusiveAdded = $false   
    $UpdatesToDownload = New-Object -ComObject Microsoft.Update.UpdateColl
    Write-OutputWithTimeStamp "Checking search results:"
    For ($i = 0; $i -lt $($SearchResult.Updates).Count; $i++) {
        $Update = $SearchResult.Updates[$i]
        $AddThisUpdate = $false        
        If ($ExclusiveAdded) {
            Write-Output "$($i + 1) > skipping: '$($update.Title)' because an exclusive update has already been selected."
        }
        Else {
            $AddThisUpdate = $true
        }        
        if ($ExcludePreviewUpdates -and $update.Title -like '*Preview*') {
            Write-Output "$($i + 1) > Skipping: '$($update.Title)' because it is a preview update."
            $AddThisUpdate = $false
        }        
        If ($AddThisUpdate) {
            $PropertyTest = 0
            $ErrorActionPreference = 'SilentlyContinue'
            $PropertyTest = $Update.InstallationBehavior.Impact
            $ErrorActionPreference = 'Stop'
            If ($PropertyTest -eq 2) {
                If ($AtLeastOneAdded) {
                    Write-Output "$($i + 1) > skipping: '$($update.Title)' because it is exclusive and other updates are being installed first."
                    $AddThisUpdate = $false
                }
            }
        }
        If ($AddThisUpdate) {
            Write-Output "$($i + 1) > adding: '$($update.Title)'"
            $UpdatesToDownload.Add($Update) | out-null
            $AtLeastOneAdded = $true
            $ErrorActionPreference = 'SilentlyContinue'
            $PropertyTest = $Update.InstallationBehavior.Impact
            $ErrorActionPreference = 'Stop'
            If ($PropertyTest -eq 2) {
                Write-Output "This update is exclusive; skipping remaining updates"
                $ExclusiveAdded = $true
            }
        }
    }        
    $UpdatesToInstall = New-Object -ComObject Microsoft.Update.UpdateColl
    Write-OutputWithTimeStamp "Downloading updates..."
    $Downloader = $UpdateSession.CreateUpdateDownloader()
    $Downloader.Updates = $UpdatesToDownload
    $Downloader.Download()
    Write-OutputWithTimeStamp "Successfully downloaded updates:"        
    For ($i = 0; $i -lt $UpdatesToDownload.Count; $i++) {
        $Update = $UpdatesToDownload[$i]
        If ($Update.IsDownloaded -eq $true) {
            Write-Output "$($i + 1) > $($update.title)"
            $UpdatesToInstall.Add($Update) | out-null
        }
    }        
    If ($UpdatesToInstall.Count -gt 0) {
        Write-OutputWithTimeStamp "Now installing updates..."
        $Installer = New-Object -ComObject Microsoft.Update.Installer
        $Installer.Updates = $UpdatesToInstall
        $InstallationResult = $Installer.Install()
        $Text = ConvertFrom-InstallationResult -Result $InstallationResult.ResultCode
        Write-OutputWithTimeStamp "Installation Result: $($Text)"        
        If ($InstallationResult.RebootRequired) {
            Write-OutputWithTimeStamp "Atleast one update requires a reboot to complete the installation."
        }
    }
}
Else {
    Write-OutputWithTimeStamp "No missing updates found."
}

If ($service -eq 'MU') {
    Reg.exe DELETE "HKLM\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate\AU" /v AllowMUUpdateService /f
}
Elseif ($Service -eq 'WSUS' -and $WSUSServer) {
    reg.exe DELETE "HKLM\Software\Policies\Microsoft\Windows\WindowsUpdate" /v WUServer /f
    reg.exe DELETE "HKLM\Software\Policies\Microsoft\Windows\WindowsUpdate" /v WUStatusServer /f
}
Stop-Transcript

variables.restartVmScript:
param(
    [string]$ResourceManagerUri,
    [string]$UserAssignedIdentityClientId,
    [string]$VmResourceId
)

$ErrorActionPreference = 'Stop'
$WarningPreference = 'SilentlyContinue'

Try {
    # Fix the resource manager URI since only AzureCloud contains a trailing slash
    $ResourceManagerUriFixed = if($ResourceManagerUri[-1] -eq '/'){$ResourceManagerUri.Substring(0,$ResourceManagerUri.Length - 1)} else {$ResourceManagerUri}

    # Get an access token for Azure resources
    $AzureManagementAccessToken = (Invoke-RestMethod `
        -Headers @{Metadata="true"} `
        -Uri $('http://169.254.169.254/metadata/identity/oauth2/token?api-version=2018-02-01&resource=' + $ResourceManagerUriFixed + '&client_id=' + $UserAssignedIdentityClientId)).access_token

    # Set header for Azure Management API
    $AzureManagementHeader = @{
        'Content-Type'='application/json'
        'Authorization'='Bearer ' + $AzureManagementAccessToken
    }
    
    # Restart the VM
    $null = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Post' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/restart?api-version=2024-03-01')
    $VmStatus = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Get' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/instanceView?api-version=2024-03-01')
    $provisioningState = ($VMStatus.statuses | Where-Object {$_.code -like 'PowerState*'}).code
    While ($provisioningState -ne "PowerState/running") {
        Start-Sleep -Seconds 5
        $VmStatus = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Get' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/instanceView?api-version=2024-03-01')
        $provisioningState = ($VMStatus.statuses | Where-Object {$_.code -like 'PowerState*'}).code
    }
    Start-Sleep -Seconds 15   
}
catch {
    throw
}

variables.customizationScript:
param(
  [string]$APIVersion,
  [string]$Arguments='',
  [string]$BlobStorageSuffix,
  [string]$BuildDir='',
  [string]$Name,
  [string]$Uri,
  [string]$UserAssignedIdentityClientId
)

function Write-OutputWithTimeStamp {
  param(
      [string]$Message
  )    
  $Timestamp = Get-Date -Format 'MM/dd/yyyy HH:mm:ss'
  $Entry = '[' + $Timestamp + '] ' + $Message
  Write-Output $Entry
}

Function Split-ArgumentString {
    param (
        [string]$ArgumentString
    )

    if ([string]::IsNullOrWhiteSpace($ArgumentString)) {
        return @()
    }

    # For PowerShell execution with &, we want individual arguments, not combined ones
    $arguments = @()
    $currentArg = ""
    $inQuotes = $false
    
    for ($i = 0; $i -lt $ArgumentString.Length; $i++) {
        $char = $ArgumentString[$i]
        
        if ($char -eq '"' -and ($i -eq 0 -or $ArgumentString[$i-1] -ne '\')) {
            $inQuotes = !$inQuotes
            $currentArg += $char
        }
        elseif ($char -eq ' ' -and !$inQuotes) {
            if ($currentArg.Length -gt 0) {
                # Handle boolean conversion
                $value = $currentArg.Trim('"')
                if ($value -eq 'true') {
                    $arguments += '$true'
                }
                elseif ($value -eq 'false') {
                    $arguments += '$false'
                }
                else {
                    $arguments += $value
                }
                $currentArg = ""
            }
        }
        else {
            $currentArg += $char
        }
    }
    
    # Add the last argument
    if ($currentArg.Length -gt 0) {
        $value = $currentArg.Trim('"')
        if ($value -eq 'true') {
            $arguments += '$true'
        }
        elseif ($value -eq 'false') {
            $arguments += '$false'
        }
        else {
            $arguments += $value
        }
    }
    
    return $arguments
}

Function ConvertTo-ParametersSplat {
    param (
        [string]$ArgumentString
    )

    if ([string]::IsNullOrWhiteSpace($ArgumentString)) {
        return @{}
    }

    $tokens = Split-ArgumentString -ArgumentString $ArgumentString
    $parameters = @{}
    
    $i = 0
    while ($i -lt $tokens.Count) {
        $token = $tokens[$i]
        
        # If this is a parameter (starts with -)
        if ($token -match '^-(\w+)$') {
            $paramName = $matches[1]  # Remove the dash
            
            # Check if there's a value following this parameter
            if (($i + 1) -lt $tokens.Count -and $tokens[$i + 1] -notmatch '^-\w+$') {
                # Parameter with value
                $i++  # Move to the value
                $value = $tokens[$i]
                
                # Handle PowerShell booleans
                if ($value -eq '$true') {
                    $parameters[$paramName] = $true
                }
                elseif ($value -eq '$false') {
                    $parameters[$paramName] = $false
                }
                else {
                    # Remove quotes if present
                    $cleanValue = $value.Trim('"')
                    $parameters[$paramName] = $cleanValue
                }
            }
            else {
                # This is a switch parameter (no value)
                $parameters[$paramName] = $true
            }
        }
        else {
            # Handle positional arguments (rare in this context)
            # You could add logic here if needed
        }
        
        $i++
    }
    
    return $parameters
}

Start-Transcript -Path "$env:SystemRoot\Logs\$Name.log" -Force
Write-OutputWithTimeStamp "Starting '$Name' script with the following parameters."
Write-Output ( $PSBoundParameters | Format-Table -AutoSize )
If ($Arguments -eq '') { $Arguments = $null }
If ($BuildDir -ne '') {
  $TempDir = Join-Path $BuildDir -ChildPath $Name
} Else {
  $TempDir = Join-Path $Env:TEMP -ChildPath $Name
}
New-Item -Path $TempDir -ItemType Directory -Force | Out-Null
$WebClient = New-Object System.Net.WebClient
If ($Uri -match $BlobStorageSuffix -and $UserAssignedIdentityClientId -ne '') {
  Write-OutputWithTimeStamp "Getting access token for '$Uri' using User Assigned Identity."
  $StorageEndpoint = ($Uri -split "://")[0] + "://" + ($Uri -split "/")[2] + "/"
  $TokenUri = "http://169.254.169.254/metadata/identity/oauth2/token?api-version=$APIVersion&resource=$StorageEndpoint&client_id=$UserAssignedIdentityClientId"
  $AccessToken = ((Invoke-WebRequest -Headers @{Metadata = $true } -Uri $TokenUri -UseBasicParsing).Content | ConvertFrom-Json).access_token
  $WebClient.Headers.Add('x-ms-version', '2017-11-09')
  $webClient.Headers.Add("Authorization", "Bearer $AccessToken")
}
$SourceFileName = ($Uri -Split "/")[-1]
Write-OutputWithTimeStamp "Downloading '$Uri' to '$TempDir'."
$DestFile = Join-Path -Path $TempDir -ChildPath $SourceFileName
try {
  $webClient.DownloadFile("$Uri", "$DestFile")
} catch {
  Write-OutputWithTimeStamp "Download failed with exception: $($_.Exception.GetType().FullName): $($_.Exception.Message)"
  if ($_.Exception.InnerException) {
    Write-OutputWithTimeStamp "Inner exception: $($_.Exception.InnerException.Message)"
  }
  Stop-Transcript
  Exit 1
}
Start-Sleep -Seconds 10
If (!(Test-Path -Path $DestFile)) { Write-Error "Failed to download $SourceFileName"; Exit 1 }
Write-OutputWithTimeStamp 'Finished downloading'
Set-Location -Path $TempDir
$Ext = [System.IO.Path]::GetExtension($DestFile).ToLower().Replace('.','')
switch ($Ext) {
  'exe' {
      If ($Arguments) {
        Write-OutputWithTimeStamp "Executing '`"$DestFile`" $Arguments'"
        $Install = Start-Process -FilePath "$DestFile" -ArgumentList (Split-ArgumentString -ArgumentString $Arguments) -NoNewWindow -Wait -PassThru
        Write-OutputWithTimeStamp "Installation ended with exit code $($Install.ExitCode)."
      }
      Else {
        Write-OutputWithTimeStamp "Executing `"$DestFile`""
        $Install = Start-Process -FilePath "$DestFile" -NoNewWindow -Wait -PassThru
        Write-OutputWithTimeStamp "Installation ended with exit code $($Install.ExitCode)."
      }      
    }
  'msi' {
    If ($Arguments) {
      $Arguments = Split-ArgumentString -ArgumentString $Arguments
      If ($Arguments -notcontains $DestFile) {
        $InstallArg = "/i $DestFile"
        $Arguments = @($InstallArg) + $Arguments
      }
      Write-OutputWithTimeStamp "Executing 'msiexec.exe $Arguments'"
      $MsiExec = Start-Process -FilePath msiexec.exe -ArgumentList $Arguments -Wait -PassThru
      Write-OutputWithTimeStamp "Installation ended with exit code $($MsiExec.ExitCode)."
    }
    Else {
      Write-OutputWithTimeStamp "Executing 'msiexec.exe /i $DestFile /qn'"
      $MsiExec = Start-Process -FilePath msiexec.exe -ArgumentList "/i $DestFile /qn" -Wait -PassThru
      Write-OutputWithTimeStamp "Installation ended with exit code $($MsiExec.ExitCode)."
    }    
  }
  'bat' {
    If ($Arguments) {
      Write-OutputWithTimeStamp "Executing 'cmd.exe `"$DestFile`" $Arguments'"
      $Arguments = Split-ArgumentString -ArgumentString $Arguments
      If ($Arguments -notcontains $DestFile) {
        $Arguments = @("$DestFile") + $Arguments
      }
      Start-Process -FilePath cmd.exe -ArgumentList $Arguments -Wait
    }
    Else {
      Write-OutputWithTimeStamp "Executing 'cmd.exe `"$DestFile`"'"
      Start-Process -FilePath cmd.exe -ArgumentList "`"$DestFile`"" -Wait
    }
  }
  'ps1' {
    If ($Arguments) {
      Write-OutputWithTimeStamp "Calling PowerShell Script '$DestFile' with arguments '$Arguments'"
      $parameterSplat = ConvertTo-ParametersSplat -ArgumentString $Arguments
      & $DestFile @parameterSplat
    }
    Else {
      Write-OutputWithTimeStamp "Calling PowerShell Script '$DestFile'"
      & $DestFile
    }
  }
